import { useState } from 'react';
import { useAuth } from '../context/AuthContext';
import API from '../api/axios';
import styles from '../styles/ProfilePage.module.css';

function ProfilePage() {
  const { user, setUser } = useAuth();
  const [name, setName] = useState(user?.name || '');
  const [bio, setBio] = useState(user?.bio || '');
  const [profilePic, setProfilePic] = useState(null);
  const [imagePreview, setImagePreview] = useState('');
  const [currentPassword, setCurrentPassword] = useState('');
  const [newPassword, setNewPassword] = useState('');
  const [message, setMessage] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  // Updated to Render backend URL
  const picSrc = user?.profilePic
    ? `https://gamefolio-7i5e.onrender.com/uploads/${user.profilePic}`
    : null;

  const getUserInitials = () => {
    if (!user?.name) return '🎮';
    return user.name.charAt(0).toUpperCase();
  };

  const handleImageChange = (e) => {
    const file = e.target.files[0];
    if (file) {
      setProfilePic(file);
      setImagePreview(URL.createObjectURL(file));
    }
  };

  const handleProfileUpdate = async (e) => {
    e.preventDefault();
    setLoading(true);
    setMessage('');
    setError('');
    
    const formData = new FormData();
    formData.append('name', name);
    formData.append('bio', bio);
    if (profilePic) formData.append('profilePic', profilePic);

    try {
      const { data } = await API.put('/auth/profile', formData);
      setUser(data);
      setMessage('Profile updated successfully!');
      setImagePreview('');
      setProfilePic(null);
    } catch (err) {
      setError(err.response?.data?.message || 'Update failed');
    } finally {
      setLoading(false);
    }
  };

  const handlePasswordChange = async (e) => {
    e.preventDefault();
    setLoading(true);
    setMessage('');
    setError('');

    try {
      await API.put('/auth/change-password', { currentPassword, newPassword });
      setMessage('Password changed successfully!');
      setCurrentPassword('');
      setNewPassword('');
    } catch (err) {
      setError(err.response?.data?.message || 'Password change failed');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className={styles.container}>
      <div className={styles.profileHeader}>
        <h2>My Profile</h2>
      </div>
      
      {message && <div className={styles.successMsg}>{message}</div>}
      {error && <div className={styles.errorMsg}>{error}</div>}

      <div className={styles.avatarSection}>
        {imagePreview || picSrc ? (
          <img 
            src={imagePreview || picSrc} 
            alt="Profile" 
            className={styles.avatar}
          />
        ) : (
          <div className={styles.avatarPlaceholder}>
            <span className={styles.avatarEmoji}>{getUserInitials()}</span>
          </div>
        )}
      </div>

      <div className={styles.card}>
        <h3>✏️ Edit Profile</h3>
        <form onSubmit={handleProfileUpdate}>
          <div className={styles.formGroup}>
            <label>Display Name</label>
            <input
              type="text"
              value={name}
              onChange={(e) => setName(e.target.value)}
              placeholder="Your display name"
              required
            />
          </div>
          
          <div className={styles.formGroup}>
            <label>Bio</label>
            <textarea
              value={bio}
              onChange={(e) => setBio(e.target.value)}
              placeholder="Tell us about yourself..."
              rows="4"
            />
          </div>
          
          <div className={styles.formGroup}>
            <label>Profile Picture</label>
            <input
              type="file"
              accept="image/*"
              onChange={handleImageChange}
              className={styles.fileInput}
            />
            <small className={styles.hint}>Upload a JPG, PNG, or GIF image (max 5MB)</small>
          </div>
          
          <button type="submit" className={styles.submitBtn} disabled={loading}>
            {loading ? 'Saving...' : '💾 Save Profile'}
          </button>
        </form>
      </div>

      <div className={styles.card}>
        <h3>🔒 Change Password</h3>
        <form onSubmit={handlePasswordChange}>
          <div className={styles.formGroup}>
            <label>Current Password</label>
            <input
              type="password"
              value={currentPassword}
              onChange={(e) => setCurrentPassword(e.target.value)}
              placeholder="Enter current password"
              required
            />
          </div>
          
          <div className={styles.formGroup}>
            <label>New Password (min 6 chars)</label>
            <input
              type="password"
              value={newPassword}
              onChange={(e) => setNewPassword(e.target.value)}
              placeholder="Enter new password"
              required
              minLength="6"
            />
          </div>
          
          <button type="submit" className={styles.submitBtn} disabled={loading}>
            {loading ? 'Changing...' : '🔑 Change Password'}
          </button>
        </form>
      </div>
    </div>
  );
}

export default ProfilePage;
